// 1. Sadə Namespace
namespace MathUtils {
  export function add(a: number, b: number): number {
    return a + b;
  }
  export function subtract(a: number, b: number): number {
    return a - b;
  }
}
console.log(MathUtils.add(5, 3)); // Çıxış: 8
console.log(MathUtils.subtract(5, 3)); // Çıxış: 2

// 2. Nested Namespaces
namespace Geometry {
  export namespace Circle {
    export function area(radius: number): number {
      return 3.14 * radius * radius;
    }
  }
  export namespace Square {
    export function area(side: number): number {
      return side * side;
    }
  }
}
console.log(Geometry.Circle.area(5)); // Çıxış: 78.5
console.log(Geometry.Square.area(4)); // Çıxış: 16

// 3. Namespace ilə interfeys və sinif
namespace UserManagement {
  export interface User {
    name: string;
    age: number;
  }
  export class UserProfile {
    constructor(public user: User) {}
    display(): string {
      return `Name: ${this.user.name}, Age: ${this.user.age}`;
    }
  }
}
const user: UserManagement.User = { name: "Alice", age: 30 };
const profile = new UserManagement.UserProfile(user);
console.log(profile.display()); // Çıxış: Name: Alice, Age: 30

// 4. Bir neçə faylda Namespace (səhvən ayrı fayl simulyasiyası)
namespace Validation {
  export function isValidEmail(email: string): boolean {
    return email.includes("@");
  }
}
// Başqa faylda olduğunu təsəvvür edin
namespace Validation {
  export function isValidAge(age: number): boolean {
    return age >= 0;
  }
}
console.log(Validation.isValidEmail("test@example.com")); // Çıxış: true
console.log(Validation.isValidAge(25)); // Çıxış: true

// Sadə mağaza sistemi
namespace Store {
  export interface Product {
    id: string;
    name: string;
    price: number;
  }
  export namespace Inventory {
    export function addProduct(products: Product[], product: Product): Product[] {
      return [...products, product];
    }
    export function getTotalPrice(products: Product[]): number {
      return products.reduce((total, p) => total + p.price, 0);
    }
  }
}
const products: Store.Product[] = [];
const laptop: Store.Product = { id: "P001", name: "Laptop", price: 999 };
const updatedProducts = Store.Inventory.addProduct(products, laptop);
console.log(Store.Inventory.getTotalPrice(updatedProducts)); // Çıxış: 999

// Namespace ilə istifadəçi idarəetməsi
namespace Store {
  export namespace User {
    export function greet(user: Product): string {
      return `Welcome, ${user.name}!`;
    }
  }
}
console.log(Store.User.greet(laptop)); // Çıxış: Welcome, Laptop!

// Modul ilə müqayisə
// Namespace nümunəsi
namespace Logger {
  export function log(message: string): void {
    console.log(message);
  }
}
Logger.log("Namespace log"); // Çıxış: Namespace log

// Eyni funksionallıq modulla
export function log(message: string): void {
  console.log(message);
}
log("Module log"); // Çıxış: Module log

